package com.example.oidcclient.security;

import com.example.oidcclient.oidc.OidcAuthenticationFilter;
import com.example.oidcclient.oidc.OidcClient;
import com.example.oidcclient.oidc.OidcProperties;
import jakarta.servlet.http.HttpServletResponse;
import org.springframework.context.annotation.Bean;
import org.springframework.context.annotation.Configuration;
import org.springframework.security.config.Customizer;
import org.springframework.security.config.annotation.web.builders.HttpSecurity;
import org.springframework.security.config.annotation.web.configuration.EnableWebSecurity;
import org.springframework.security.web.SecurityFilterChain;
import org.springframework.security.web.authentication.UsernamePasswordAuthenticationFilter;
import org.springframework.security.web.util.matcher.AntPathRequestMatcher;

@Configuration
@EnableWebSecurity
public class SecurityConfig {

    @Bean
    public SecurityFilterChain filterChain(HttpSecurity http, OidcAuthenticationFilter oidcAuthenticationFilter) throws Exception {
        http
            .csrf(csrf -> csrf.ignoringRequestMatchers(new AntPathRequestMatcher("/oidc/callback")))
            .authorizeHttpRequests(auth -> auth
                .requestMatchers("/login", "/logout", "/oidc/**", "/error").permitAll()
                .anyRequest().authenticated()
            )
            .addFilterBefore(oidcAuthenticationFilter, UsernamePasswordAuthenticationFilter.class)
            .exceptionHandling(ex -> ex.authenticationEntryPoint((request, response, authException) -> {
                response.setStatus(HttpServletResponse.SC_FOUND);
                response.setHeader("Location", "/login");
            }))
            .httpBasic(Customizer.withDefaults())
            .formLogin(form -> form.disable());

        return http.build();
    }

    @Bean
    public OidcAuthenticationFilter oidcAuthenticationFilter(OidcClient oidcClient, OidcProperties properties) {
        return new OidcAuthenticationFilter(oidcClient, properties);
    }
}

