public class OidcAuthenticationFilter extends OncePerRequestFilter {

    public static final String SESSION_ATTR_USER = "OIDC_USER";
    public static final String SESSION_ATTR_TOKENS = "OIDC_TOKENS";
    public static final String SESSION_ATTR_STATE = "OIDC_STATE";
    public static final String SESSION_ATTR_NONCE = "OIDC_NONCE";

    private final OidcClient oidcClient;
    private final OidcProperties properties;
    private final SecureRandom secureRandom = new SecureRandom();
    private final AntPathMatcher pathMatcher = new AntPathMatcher();
    private final ObjectMapper objectMapper = new ObjectMapper();

    public OidcAuthenticationFilter(OidcClient oidcClient, OidcProperties properties) {
        this.oidcClient = oidcClient;
        this.properties = properties;
    }

    @Override
    protected boolean shouldNotFilter(HttpServletRequest request) {
        String path = request.getRequestURI();
        if (pathMatcher.match("/oidc/callback", path)) return false;
        if (pathMatcher.match("/login", path)) return false;
        if (pathMatcher.match("/logout", path)) return false;
        return false;
    }

    @Override
    protected void doFilterInternal(HttpServletRequest request, HttpServletResponse response, FilterChain filterChain)
        throws ServletException, IOException {

        String path = request.getRequestURI();

        if (pathMatcher.match("/login", path)) {
            handleLogin(request, response);
            return;
        }

        if (pathMatcher.match("/logout", path)) {
            handleLogout(request, response);
            return;
        }

        if (pathMatcher.match("/oidc/callback", path)) {
            handleCallback(request, response);
            return;
        }

        HttpSession session = request.getSession(false);
        if (session != null) {
            OidcUserSession userSession = (OidcUserSession) session.getAttribute(SESSION_ATTR_USER);
            if (userSession != null && userSession.getExpiresAtEpochSeconds() > Instant.now().getEpochSecond()) {
                ensureSpringSecurityAuthentication(request, userSession);
            }
        }

        filterChain.doFilter(request, response);
    }

    private void handleLogin(HttpServletRequest request, HttpServletResponse response) throws IOException {
        HttpSession session = request.getSession(true);

        String state = randomUrlSafe(32);
        String nonce = randomUrlSafe(32);

        session.setAttribute(SESSION_ATTR_STATE, state);
        session.setAttribute(SESSION_ATTR_NONCE, nonce);

        String redirectTo = request.getParameter("redirect");
        if (redirectTo != null && !redirectTo.isBlank()) {
            session.setAttribute("POST_LOGIN_REDIRECT", redirectTo);
        }

        String authorizationUrl =
            properties.getAuthorizationEndpoint()
                + "?response_type=code"
                + "&client_id=" + url(properties.getClientId())
                + "&redirect_uri=" + url(properties.getRedirectUri())
                + "&scope=" + url(properties.getScope())
                + "&state=" + url(state)
                + "&nonce=" + url(nonce);

        response.setStatus(HttpServletResponse.SC_FOUND);
        response.setHeader(HttpHeaders.LOCATION, authorizationUrl);
    }

    private void handleLogout(HttpServletRequest request, HttpServletResponse response) throws IOException {
        HttpSession session = request.getSession(false);
        if (session != null) {
            session.invalidate();
        }
        String target = properties.getPostLogoutRedirect();
        response.setStatus(HttpServletResponse.SC_FOUND);
        response.setHeader(HttpHeaders.LOCATION, target);
    }

    private void handleCallback(HttpServletRequest request, HttpServletResponse response) throws IOException {
        HttpSession session = request.getSession(false);
        if (session == null) {
            response.sendError(HttpServletResponse.SC_UNAUTHORIZED, "Missing session");
            return;
        }

        String code = request.getParameter("code");
        String state = request.getParameter("state");
        String error = request.getParameter("error");
        String errorDescription = request.getParameter("error_description");

        if (error != null) {
            response.sendError(HttpServletResponse.SC_UNAUTHORIZED, "OIDC error: " + error + " " + (errorDescription != null ? errorDescription : ""));
            return;
        }

        if (code == null || code.isBlank()) {
            response.sendError(HttpServletResponse.SC_BAD_REQUEST, "Missing code");
            return;
        }

        String expectedState = (String) session.getAttribute(SESSION_ATTR_STATE);
        if (expectedState == null || !Objects.equals(expectedState, state)) {
            response.sendError(HttpServletResponse.SC_UNAUTHORIZED, "Invalid state");
            return;
        }

        String expectedNonce = (String) session.getAttribute(SESSION_ATTR_NONCE);

        OidcTokenResponse tokenResponse = oidcClient.exchangeAuthorizationCode(code);

        Map<String, Object> idTokenClaims = oidcClient.parseIdTokenClaims(tokenResponse.getIdToken());
        if (expectedNonce != null) {
            Object nonceClaim = idTokenClaims.get("nonce");
            if (nonceClaim == null || !Objects.equals(String.valueOf(nonceClaim), expectedNonce)) {
                response.sendError(HttpServletResponse.SC_UNAUTHORIZED, "Invalid nonce");
                return;
            }
        }

        String sub = idTokenClaims.get("sub") != null ? String.valueOf(idTokenClaims.get("sub")) : null;
        String preferredUsername = idTokenClaims.get("preferred_username") != null ? String.valueOf(idTokenClaims.get("preferred_username")) : null;
        String email = idTokenClaims.get("email") != null ? String.valueOf(idTokenClaims.get("email")) : null;
        String name = idTokenClaims.get("name") != null ? String.valueOf(idTokenClaims.get("name")) : null;

        long now = Instant.now().getEpochSecond();
        long expiresAt = now + Math.max(1, tokenResponse.getExpiresIn());

        OidcUserSession userSession = new OidcUserSession();
        userSession.setSubject(sub);
        userSession.setPreferredUsername(preferredUsername);
        userSession.setEmail(email);
        userSession.setName(name);
        userSession.setIdTokenClaims(idTokenClaims);
        userSession.setExpiresAtEpochSeconds(expiresAt);

        session.setAttribute(SESSION_ATTR_TOKENS, tokenResponse);
        session.setAttribute(SESSION_ATTR_USER, userSession);

        ensureSpringSecurityAuthentication(request, userSession);

        String target = (String) session.getAttribute("POST_LOGIN_REDIRECT");
        if (target == null || target.isBlank()) target = properties.getPostLoginRedirect();

        response.setStatus(HttpServletResponse.SC_FOUND);
        response.setHeader(HttpHeaders.LOCATION, target);
    }

    private void ensureSpringSecurityAuthentication(HttpServletRequest request, OidcUserSession userSession) {
        Authentication existing = SecurityContextHolder.getContext().getAuthentication();
        if (existing != null && existing.isAuthenticated()) return;

        String principal = userSession.getPreferredUsername() != null ? userSession.getPreferredUsername()
            : (userSession.getEmail() != null ? userSession.getEmail()
            : (userSession.getSubject() != null ? userSession.getSubject() : "user"));

        List<SimpleGrantedAuthority> authorities = Collections.singletonList(new SimpleGrantedAuthority("ROLE_USER"));
        UsernamePasswordAuthenticationToken auth = new UsernamePasswordAuthenticationToken(principal, "N/A", authorities);
        auth.setDetails(new WebAuthenticationDetailsSource().buildDetails(request));
        SecurityContextHolder.getContext().setAuthentication(auth);
    }

    private String randomUrlSafe(int bytes) {
        byte[] b = new byte[bytes];
        secureRandom.nextBytes(b);
        return Base64.getUrlEncoder().withoutPadding().encodeToString(b);
    }

    private String url(String s) {
        return URLEncoder.encode(s, StandardCharsets.UTF_8);
    }
}

package com.example.oidcclient.oidc;

import com.fasterxml.jackson.core.type.TypeReference;
import com.fasterxml.jackson.databind.ObjectMapper;
import org.springframework.http.*;
import org.springframework.stereotype.Component;
import org.springframework.util.LinkedMultiValueMap;
import org.springframework.util.MultiValueMap;
import org.springframework.web.client.RestClientException;
import org.springframework.web.client.RestTemplate;

import java.nio.charset.StandardCharsets;
import java.util.Base64;
import java.util.Map;

@Component
public class OidcClient {

    private final OidcProperties properties;
    private final RestTemplate restTemplate;
    private final ObjectMapper objectMapper;

    public OidcClient(OidcProperties properties) {
        this.properties = properties;
        this.restTemplate = new RestTemplate();
        this.objectMapper = new ObjectMapper();
    }

    public OidcTokenResponse exchangeAuthorizationCode(String code) {
        HttpHeaders headers = new HttpHeaders();
        headers.setContentType(MediaType.APPLICATION_FORM_URLENCODED);
        headers.setAccept(MediaType.parseMediaTypes("application/json"));

        String basic = properties.getClientId() + ":" + properties.getClientSecret();
        String basicEncoded = Base64.getEncoder().encodeToString(basic.getBytes(StandardCharsets.UTF_8));
        headers.set(HttpHeaders.AUTHORIZATION, "Basic " + basicEncoded);

        MultiValueMap<String, String> form = new LinkedMultiValueMap<>();
        form.add("grant_type", "authorization_code");
        form.add("code", code);
        form.add("redirect_uri", properties.getRedirectUri());

        HttpEntity<MultiValueMap<String, String>> entity = new HttpEntity<>(form, headers);

        ResponseEntity<Map> resp;
        try {
            resp = restTemplate.exchange(properties.getTokenEndpoint(), HttpMethod.POST, entity, Map.class);
        } catch (RestClientException e) {
            throw new IllegalStateException("Token endpoint call failed", e);
        }

        if (!resp.getStatusCode().is2xxSuccessful() || resp.getBody() == null) {
            throw new IllegalStateException("Token endpoint returned " + resp.getStatusCode());
        }

        Map<String, Object> body = resp.getBody();
        OidcTokenResponse tr = new OidcTokenResponse();
        tr.setAccessToken(getString(body, "access_token"));
        tr.setIdToken(getString(body, "id_token"));
        tr.setRefreshToken(getString(body, "refresh_token"));
        tr.setTokenType(getString(body, "token_type"));
        tr.setScope(getString(body, "scope"));
        tr.setExpiresIn(getLong(body, "expires_in", 3600L));
        return tr;
    }

    public Map<String, Object> fetchUserInfo(String accessToken) {
        HttpHeaders headers = new HttpHeaders();
        headers.setBearerAuth(accessToken);
        headers.setAccept(MediaType.parseMediaTypes("application/json"));

        HttpEntity<Void> entity = new HttpEntity<>(headers);

        ResponseEntity<Map> resp = restTemplate.exchange(properties.getUserinfoEndpoint(), HttpMethod.GET, entity, Map.class);
        if (!resp.getStatusCode().is2xxSuccessful() || resp.getBody() == null) {
            throw new IllegalStateException("Userinfo endpoint returned " + resp.getStatusCode());
        }
        return resp.getBody();
    }

    public Map<String, Object> parseIdTokenClaims(String idToken) {
        if (idToken == null || idToken.isBlank()) throw new IllegalArgumentException("Missing id_token");
        String[] parts = idToken.split("\\.");
        if (parts.length < 2) throw new IllegalArgumentException("Invalid JWT");

        String payloadJson = new String(Base64.getUrlDecoder().decode(parts[1]), StandardCharsets.UTF_8);
        try {
            return objectMapper.readValue(payloadJson, new TypeReference<Map<String, Object>>() {});
        } catch (Exception e) {
            throw new IllegalArgumentException("Unable to parse id_token claims", e);
        }
    }

    private String getString(Map<String, Object> m, String k) {
        Object v = m.get(k);
        return v == null ? null : String.valueOf(v);
    }

    private long getLong(Map<String, Object> m, String k, long def) {
        Object v = m.get(k);
        if (v == null) return def;
        if (v instanceof Number n) return n.longValue();
        try { return Long.parseLong(String.valueOf(v)); } catch (Exception e) { return def; }
    }
}

