package com.example.oidcclient.web;

import com.example.oidcclient.oidc.OidcAuthenticationFilter;
import com.example.oidcclient.oidc.OidcTokenResponse;
import com.example.oidcclient.oidc.OidcUserSession;
import com.example.oidcclient.oidc.OidcClient;
import jakarta.servlet.http.HttpSession;
import org.springframework.http.MediaType;
import org.springframework.web.bind.annotation.GetMapping;
import org.springframework.web.bind.annotation.RestController;

import java.util.LinkedHashMap;
import java.util.Map;

@RestController
public class MeController {

    private final OidcClient oidcClient;

    public MeController(OidcClient oidcClient) {
        this.oidcClient = oidcClient;
    }

    @GetMapping(value = "/me", produces = MediaType.APPLICATION_JSON_VALUE)
    public Map<String, Object> me(HttpSession session) {
        Map<String, Object> out = new LinkedHashMap<>();
        OidcUserSession user = (OidcUserSession) session.getAttribute(OidcAuthenticationFilter.SESSION_ATTR_USER);
        OidcTokenResponse tokens = (OidcTokenResponse) session.getAttribute(OidcAuthenticationFilter.SESSION_ATTR_TOKENS);

        out.put("user", user);
        if (tokens != null) {
            out.put("tokenType", tokens.getTokenType());
            out.put("scope", tokens.getScope());
            out.put("expiresIn", tokens.getExpiresIn());
        }
        return out;
    }

    @GetMapping(value = "/userinfo", produces = MediaType.APPLICATION_JSON_VALUE)
    public Map<String, Object> userinfo(HttpSession session) {
        OidcTokenResponse tokens = (OidcTokenResponse) session.getAttribute(OidcAuthenticationFilter.SESSION_ATTR_TOKENS);
        if (tokens == null || tokens.getAccessToken() == null) throw new IllegalStateException("Not authenticated");
        return oidcClient.fetchUserInfo(tokens.getAccessToken());
    }
}

