package com.example.oidcclient.web;

import org.springframework.http.HttpHeaders;
import org.springframework.http.HttpStatus;
import org.springframework.http.ResponseEntity;
import org.springframework.web.bind.annotation.GetMapping;
import org.springframework.web.bind.annotation.RequestParam;
import org.springframework.web.bind.annotation.RestController;

@RestController
public class LoginController {

    @GetMapping("/start-login")
    public ResponseEntity<Void> startLogin(@RequestParam(value = "redirect", required = false) String redirect) {
        String location = "/login" + (redirect != null && !redirect.isBlank() ? "?redirect=" + redirect : "");
        return ResponseEntity.status(HttpStatus.FOUND).header(HttpHeaders.LOCATION, location).build();
    }
}

